// Chat.jsx - White theme like AI Advisor interface
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { LogoMark } from '../components/Logo';
import s from './Chat.module.css';

const EXAMPLES = [
  'Which campaign had the best ROI?',
  'Compare retention across iOS and Android',
  'Forecast LTV for specific segments',
  'Analyze user drop-off after Day 7',
];

export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => { loadConversations(); }, []);

  const loadConversations = async () => {
    try {
      const r = await axios.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch {}
  };

  const loadConversation = async (convId) => {
    try {
      const r = await axios.get(`/conversations/${convId}/messages`);
      setMessages(r.data.messages.map(m => ({
        role: m.sender === 'user' ? 'user' : 'bot',
        text: m.content,
        time: new Date(m.timestamp).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
      })));
      setActiveConvId(convId);
    } catch {}
  };

  const newConversation = () => {
    setActiveConvId(null);
    setMessages([]);
    textareaRef.current?.focus();
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const handleInputChange = e => {
    setInput(e.target.value);
    const el = textareaRef.current;
    if (el) {
      el.style.height = 'auto';
      el.style.height = Math.min(el.scrollHeight, 140) + 'px';
    }
  };

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;
    const now = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    setMessages(prev => [...prev, { role: 'user', text, time: now }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);
    try {
      const r = await axios.post('/chat', { message: text, conversation_id: activeConvId });
      const botTime = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
      setMessages(prev => [...prev, { role: 'bot', text: r.data.response, time: botTime }]);
      if (!activeConvId && r.data.conversation_id) {
        setActiveConvId(r.data.conversation_id);
        loadConversations();
      }
    } catch {
      setMessages(prev => [...prev, { role: 'bot', text: 'Error: Unable to connect to server. Please try again.', time: new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }), isError: true }]);
    } finally {
      setLoading(false);
    }
  }, [input, loading, activeConvId]);

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const deleteConv = async (convId, e) => {
    e.stopPropagation();
    try {
      await axios.delete(`/conversations/${convId}`);
      if (activeConvId === convId) newConversation();
      loadConversations();
    } catch {}
  };

  return (
    <div className={s.layout}>
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideTop}>
          <div className={s.sideLogoRow}>
            <LogoMark size={28} />
            <span className={s.sideLogoTxt}>AWAL GPT</span>
            <button className={s.sideToggle} onClick={() => setSidebarOpen(v => !v)}>←</button>
          </div>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
            New conversation
          </button>
        </div>
        <div className={s.sideSection}>
          <div className={s.sideSectionTitle}>Examples</div>
          {EXAMPLES.map((ex, i) => (
            <button key={i} className={s.exampleBtn} onClick={() => setInput(ex)}>{ex}</button>
          ))}
        </div>
        {conversations.length > 0 && (
          <div className={s.sideSection}>
            <div className={s.sideSectionTitle}>History</div>
            {conversations.map(c => (
              <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                <button className={s.convDel} onClick={e => deleteConv(c.id, e)}>×</button>
              </div>
            ))}
          </div>
        )}
        <div className={s.sideFooter}>
          <div className={s.userRow}>
            <div className={s.userAvatar}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{user?.username}</div>
              <div className={s.userEmail}>{user?.email}</div>
            </div>
          </div>
          <button className={s.logoutBtn} onClick={() => { logout(); nav('/'); }}>Sign out</button>
        </div>
      </aside>
      <main className={s.main}>
        <div className={s.mainHeader}>
          {!sidebarOpen && <button className={s.sideToggleMain} onClick={() => setSidebarOpen(true)}>☰</button>}
          <div className={s.mainHeaderTitle}><LogoMark size={24} /><span>AWAL GPT</span></div>
          {activeConvId && <button className={s.newChatSmall} onClick={newConversation}>+ New</button>}
        </div>
        <div className={s.messagesWrap}>
          <div className={s.messages}>
            {messages.length === 0 && (
              <div className={s.emptyState}>
                <LogoMark size={56} />
                <h2 className={s.emptyTitle}>What would you like to create?</h2>
                <p className={s.emptySub}>Ask me anything about Tamazight language, translation, or conversation.</p>
                <div className={s.emptyExamples}>
                  {EXAMPLES.map((ex, i) => (<button key={i} className={s.emptyEx} onClick={() => setInput(ex)}>{ex}</button>))}
                </div>
              </div>
            )}
            {messages.map((msg, i) => (
              <div key={i} className={`${s.msgRow} ${msg.role === 'user' ? s.msgUser : s.msgBot}`}>
                <div className={s.msgAvatar}>
                  {msg.role === 'user' ? <span className={s.avatarUser}>{user?.username?.[0]?.toUpperCase() || 'U'}</span> : <LogoMark size={30} />}
                </div>
                <div className={s.msgBody}>
                  <div className={s.msgName}>{msg.role === 'user' ? (user?.username || 'You') : 'AWAL GPT'}<span className={s.msgTime}>{msg.time}</span></div>
                  <div className={`${s.msgText} ${msg.isError ? s.msgError : ''}`}>{msg.text}</div>
                </div>
              </div>
            ))}
            {loading && (
              <div className={`${s.msgRow} ${s.msgBot}`}>
                <div className={s.msgAvatar}><LogoMark size={30} /></div>
                <div className={s.msgBody}><div className={s.msgName}>AWAL GPT</div><div className={s.typing}><span /><span /><span /></div></div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>
        <div className={s.inputArea}>
          <div className={s.inputBox}>
            <textarea ref={textareaRef} className={s.textarea} placeholder="Ask anything about Tamazight..." value={input} onChange={handleInputChange} onKeyDown={handleKeyDown} rows={1} disabled={loading} />
            <button className={s.sendBtn} onClick={sendMessage} disabled={loading || !input.trim()}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
            </button>
          </div>
          <p className={s.inputHint}>Enter to send · Shift+Enter for new line</p>
        </div>
      </main>
    </div>
  );
}
